  siteLogo: "/logo.png",
  socialBanner: "/social-banner.png",
  email: "baekki@gmail.com",
  github: "https://github.com/baekki",
  twitter: "https://twitter.com/baekki",
  linkedin: "https://www.linkedin.com/in/baekki/",
